import"./chunk-DKLAGT4O.js";var t={DetatokoSaga:{DS:{input_options:"\uD310\uC815\uFF01\u3000\uC2A4\uD0AC\uB808\uBCA8\uFF1A%{skill}\u3000\uD50C\uB798\uADF8\uFF1A%{flag}\u3000\uBAA9\uD45C\uCE58\uFF1A%{target}",modifier:"\u3000\uC218\uC815\uCE58\uFF1A%{modifier}",success:"\uBAA9\uD45C\uCE58 \uC774\uC0C1\uFF01\u3010\uC131\uACF5\u3011",failure:"\uBAA9\uD45C\uCE58 \uBBF8\uB2EC\u2026 \u3010\uC2E4\uD328\u3011"},JD:{input_options:"\uD310\uC815\uFF01\u3000\uC2A4\uD0AC\uB808\uBCA8\uFF1A%{skill}\u3000\uD50C\uB798\uADF8\uFF1A%{flag}",modifier:"\u3000\uC218\uC815\uCE58\uFF1A%{modifier}"},total_value:"\uD310\uC815\uCE58\uFF1A%{total}",less_than_flag:", \uD50C\uB798\uADF8 \uC774\uD558\uFF01 \u3010\uAE30\uB825%{will}\uC810 \uAC10\uC18C\u3011 \u3010\uD310\uC815\uCE58 \uBCC0\uACBD \uBD88\uAC00\u3011",division_by_zero_error:"0\uC73C\uB85C\uB294 \uB098\uB204\uC5B4\uC9C0\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4",table:{SST:{name:"\uCCB4\uB825 \uB099\uC778\uD45C",type:"2D6",items:["\uB2F9\uC2E0\uC740 \u3010\uB099\uC778\u3011\uC744 2\uAC1C \uBC1B\uB294\uB2E4. \uC774 \uD45C\uB97C \uB2E4\uC2DC 2\uBC88 \uAD74\uB824 \uBC1B\uC744 \u3010\uB099\uC778\u3011\uC744 \uC815\uD55C\uB2E4(\uADF8 \uACBD\uC6B0, \uB2E4\uC2DC \uC774 \uB208\uC774 \uB098\uC640\uB3C4 \u3010\uB099\uC778\u3011\uC740 \uB298\uC5B4\uB098\uC9C0 \uC54A\uB294\uB2E4).","\u3010\uC0C1\uCC98\u3011 \uC2EC\uD55C \uC0C1\uCC98\uB97C \uC785\uC5C8\uB2E4. \uC5B4\uB5BB\uAC8C\uB4E0 \uC2F8\uC6B8 \uC218\uB294 \uC788\uC9C0\uB9CC\u2026\u2026.","\u3010\uCD9C\uD608\u3011 \uD53C\uAC00 \uD758\uB7EC\uB118\uCCD0, \uB208\uC774 \uD750\uB9BF\uD558\uB2E4\u2026\u2026.","\u3010\uC1E0\uC57D\u3011 \uBAB8\uC774 \uC57D\uD574\uC838, \uADF8 \uB9C8\uC74C\uB9C8\uC800\uB3C4 \uC2DC\uB4E4\uC5B4\uBC84\uB9B4 \uAC70 \uAC19\uB2E4.","\u3010\uACE0\uD1B5\u3011 \uC544\uD514\uACFC \uAD34\uB85C\uC6C0, \uD55C\uC2EC\uD568. \uB208\uC5D0\uC11C \uB208\uBB3C\uC774 \uC0C8\uC5B4 \uB098\uC628\uB2E4.","\u3010\uCDA9\uACA9\u3011 \uB0A0\uB824\uC838\uC11C, \uBCBD\uC774\uB098 \uB098\uBB34\uC5D0 \uBD80\uB52A\uD78C\uB2E4. \uBE68\uB9AC \uC77C\uC5B4\uC11C\uC9C0 \uC54A\uC73C\uBA74.","\u3010\uD53C\uB85C\u3011 \uB2F9\uC2E0\uC758 \uC5BC\uAD74\uC5D0 \uD53C\uB85C\uC758 \uC0C9\uC774 \uAC15\uD574\uC9C4\uB2E4\u2026\u2026\uC774 \uC2F8\uC6C0\uC774 \uD798\uACA8\uC6CC\uC84C\uB2E4.","\u3010\uB178\uD638\u3011 \uC131\uAC00\uC2E0 \uACF5\uACA9\uC5D0 \uBD84\uB178\uC758 \uD568\uC131\uC744 \uC9C0\uB978\uB2E4. \uBD84\uB178\uAC00 \uC2F8\uC6C0\uC744 \uC5B4\uB835\uAC8C \uD560\uAE4C?","\u3010\uBD80\uC0C1\u3011 \uC0C1\uCC98\uB97C \uC785\uC5C8\uB2E4\u2026\u2026.","\u3010\uACBD\uC0C1\u3011 \uB2F9\uC2E0\uC758 \uD53C\uBD80\uC5D0 \uC0C1\uCC98\uAC00 \uB0A8\uC558\uB2E4. \uC774\uAC83\uB9CC\uC774\uB77C\uBA74 \uC544\uBB34\uB807\uC9C0\uB3C4 \uC54A\uB2E4.","\uAE30\uC801\uC801\uC73C\uB85C \uB2F9\uC2E0\uC740 \u3010\uB099\uC778\u3011\uC744 \uBC1B\uC9C0 \uC54A\uC558\uB2E4."]},WST:{name:"\uAE30\uB825 \uB099\uC778\uD45C",type:"2D6",items:["\uB2F9\uC2E0\uC740 \u3010\uB099\uC778\u3011\uC744 2\uAC1C \uBC1B\uB294\uB2E4. \uC774 \uD45C\uB97C \uB2E4\uC2DC 2\uBC88 \uAD74\uB824 \uBC1B\uC744 \u3010\uB099\uC778\u3011\uC744 \uC815\uD55C\uB2E4(\uADF8 \uACBD\uC6B0, \uB2E4\uC2DC \uC774 \uB208\uC774 \uB098\uC640\uB3C4 \u3010\uB099\uC778\u3011\uC740 \uB298\uC5B4\uB098\uC9C0 \uC54A\uB294\uB2E4).","\u3010\uC808\uB9DD\u3011 \uC5B4\uB5BB\uAC8C \uD558\uC9C0 \uBABB\uD558\uB294 \uC0C1\uD669. \uD76C\uB9DD\uC740 \uC0AC\uB77C\uC9C0\uACE0\u2026\u2026\uBB34\uB98E\uC744 \uAFC7\uC744 \uC218\uBC16\uC5D0 \uC5C6\uB2E4.","\u3010\uD1B5\uACE1\u3011 \uB108\uBB34\uB3C4 \uBD80\uC870\uB9AC\uD568\uC5D0, \uC5B4\uB9B0\uC544\uC774\uCC98\uB7FC \uC6B8\uC74C\uC744 \uD130\uD2B8\uB9B4 \uC218\uBC16\uC5D0 \uC5C6\uB2E4.","\u3010\uD6C4\uD68C\u3011 \uC774\uB7F4 \uC0DD\uAC01\uC740 \uC544\uB2C8\uC5C8\uB294\uB370. \uD558\uC9C0\uB9CC \uD604\uC2E4\uC740 \uBE44\uC815\uD588\uB2E4.","\u3010\uACF5\uD3EC\u3011 \uACF5\uD3EC\uC5D0 \uC0AC\uB85C\uC7A1\uD614\uB2E4! \uC801\uC774, \uC790\uC2E0\uC758 \uC190\uC774, \uBB34\uC11C\uC6CC\uC11C \uCC38\uC744 \uC218 \uC5C6\uB2E4!","\u3010\uAC08\uB4F1\u3011 \uC815\uB9D0\uB85C \uC774\uAC78\uB85C \uAD1C\uCC2E\uC740 \uAC78\uAE4C? \uBA87 \uBC88\uC774\uACE0 \uC790\uC2E0\uC5D0\uAC8C \uC758\uBB38\uC774 \uC77C\uC5B4\uB09C\uB2E4\u2026\u2026.","\u3010\uC99D\uC624\u3011 \uBD84\uB178\uC640 \uC99D\uC624\uC5D0 \uC0AC\uB85C\uC7A1\uD78C \uB2F9\uC2E0\uC740, \uBCF8\uB798\uC758 \uD798\uC744 \uBC1C\uD718\uD560 \uC218 \uC788\uC744\uAE4C?","\u3010\uB9DD\uC5F0\u3011 \uC774\uAC83\uC740 \uD604\uC2E4\uC778\uAC00? \uBABD\uB871\uD55C \uC815\uC2E0\uC73C\uB85C \uB2F9\uC2E0\uC740 \uC0DD\uAC01\uD55C\uB2E4.","\u3010\uC8FC\uC800\u3011 \uB9DD\uC124\uC784\uC744 \uAC00\uC84C\uB2E4. \uADF8\uAC83\uC740 \uC2F8\uC6B8 \uC758\uC9C0\uB97C \uB454\uD558\uAC8C \uD560 \uAC83\uC778\uAC00?","\u3010\uC545\uBABD\u3011 \uC774\uC81C\uBD80\uD130 \uB54C\uB54C\uB85C, \uB2F9\uC2E0\uC740 \uC774 \uC21C\uAC04\uC744 \uC545\uBABD\uC73C\uB85C \uBCFC \uAC83\uC774\uB2E4.","\uAE30\uC801\uC801\uC73C\uB85C \uB2F9\uC2E0\uC740 \u3010\uB099\uC778\u3011\uC744 \uBC1B\uC9C0 \uC54A\uC558\uB2E4."]},SBET:{name:"\uCCB4\uB825 \uBC30\uB4DC\uC5D4\uB529\uD45C",type:"2D6",items:["\u3010\uC0AC\uB9DD\u3011 \uB2F9\uC2E0\uC740 \uC8FD\uC5C8\uB2E4. \uB2E4\uC74C \uC138\uC158\uC5D0 \uCC38\uAC00\uD558\uAE30 \uC704\uD574\uC11C\uB294, \uD074\uB798\uC2A4 1\uAC1C\uB97C \u300E\uBAAC\uC2A4\uD130\u300F\uB098 \u300E\uC554\uD751\u300F\uC73C\uB85C \uD074\uB798\uC2A4 \uCCB4\uC778\uC9C0\uD574\uC57C\uB9CC \uD55C\uB2E4.","\u3010\uBAA9\uC228 \uAD6C\uAC78\u3011 \uB2F9\uC2E0\uC740 \uACF5\uD3EC\uB97C \uB290\uAEF4, \uBAA9\uC228\uC744 \uAD6C\uAC78\uD588\uB2E4! \uB2E4\uC74C \uC138\uC158 \uAC1C\uC2DC \uC2DC\uC5D0, \uD074\uB798\uC2A4 1\uAC1C\uAC00 \u300E\uC790\uCF54\u300F\uB85C \uBCC0\uACBD\uB41C\uB2E4!","\u3010\uB9DD\uAC01\u3011 \uB2F9\uC2E0\uC740 \uAE30\uC5B5\uC744 \uC783\uACE0, \uC6B0\uB450\uCEE4\uB2C8 \uC130\uB2E4. \uB2E4\uC74C \uC138\uC158\uC5D0 \uCC38\uAC00\uD558\uAE30 \uC704\uD574\uC11C\uB294, \uD074\uB798\uC2A4 1\uAC1C\uB97C \uBCC0\uACBD\uD574\uC57C\uB9CC \uD55C\uB2E4.","\u3010\uBE44\uADF9\u3011 \uB2F9\uC2E0\uC758 \uACF5\uACA9\uC740 \uC801\uC774 \uC544\uB2C8\uB77C \uC544\uAD70\uC744 \uB9DE\uCDC4\uB2E4! \uBAA8\uB4E0 \uAC83\uC774 \uB05D\uB0A0 \uB54C\uAE4C\uC9C0 \uB2F9\uC2E0\uC740 \uC6B0\uB450\uCEE4\uB2C8 \uC11C \uC788\uAC8C \uB41C\uB2E4. \uC784\uC758\uC758 \uC544\uAD70\uC758 \u3010\uCCB4\uB825\u3011\uC744 1D6\uC810 \uAC10\uC18C\uC2DC\uD0A8\uB2E4.","\u3010\uD3ED\uC8FC\u3011 \uB2F9\uC2E0\uC740 \uC774\uC131\uC744 \uC783\uACE0, \uCDA9\uB3D9\uC5D0 \uB530\uB77C \uD3ED\uC8FC\uD55C\uB2E4! \uAC19\uC740 \uC52C\uC5D0 \uC788\uB294 \uC804\uC6D0\uC758 \u3010\uCCB4\uB825\u3011\uC744 1D6\uC810 \uAC10\uC18C\uC2DC\uD0A8\uB2E4.","\u3010\uC804\uB77D\u3011 \uB2F9\uC2E0\uC740 \uB2E8\uC560\uC808\uBCBD\uC5D0\uC11C \uB5A8\uC5B4\uC9C4\uB2E4.","\u3010\uD3EC\uB85C\u3011 \uB2F9\uC2E0\uC740 \uC801\uC5D0\uAC8C \uC0AC\uB85C\uC7A1\uD614\uB2E4.","\u3010\uB3C4\uC8FC\u3011 \uB2F9\uC2E0\uC740 \uAC81\uC5D0 \uC9C8\uB824, \uB3D9\uB8CC\uB97C \uBC84\uB9AC\uACE0 \uB3C4\uB9DD\uCCE4\uB2E4.","\u3010\uC911\uC0C1\u3011 \uB2F9\uC2E0\uC740 \uC5B4\uCC0C\uD560 \uC218 \uC5C6\uB294 \uC0C1\uCC98\uB97C \uC785\uACE0, \uC4F0\uB7EC\uC84C\uB2E4.","\u3010\uAE30\uC808\u3011 \uB2F9\uC2E0\uC740 \uC758\uC2DD\uC744 \uC783\uC5C8\uB2E4. \uADF8\uB9AC\uACE0 \uC815\uC2E0\uC774 \uB4E4\uBA74 \uBAA8\uB4E0 \uAC83\uC774 \uB05D\uB098\uC788\uC5C8\uB2E4.","\uADF8\uB798\uB3C4 \uC544\uC9C1 \uC77C\uC5B4\uC120\uB2E4! \uB2F9\uC2E0\uC740 \uBC30\uB4DC\uC5D4\uB4DC\uB97C \uB9DE\uC774\uD558\uC9C0 \uC54A\uC558\uB2E4. \uCCB4\uB825\uC758 \u3010\uB099\uC778\u3011\uC744 1\uAC1C \uC9C0\uC6CC\uB3C4 \uC88B\uB2E4."]},WBET:{name:"\uAE30\uB825 \uBC30\uB4DC\uC5D4\uB529\uD45C",type:"2D6",items:["\u3010\uC790\uD574\u3011 \uB2F9\uC2E0\uC740 \uC2A4\uC2A4\uB85C \uC8FD\uC74C\uC744 \uACE8\uB790\uB2E4. \uB2E4\uC74C \uC138\uC158\uC5D0 \uCC38\uAC00\uD558\uAE30 \uC704\uD574\uC11C\uB294 \uD074\uB798\uC2A4 1\uAC1C\uB97C \u300E\uC554\uD751\u300F\uC73C\uB85C \uD074\uB798\uC2A4 \uCCB4\uC778\uC9C0\uD574\uC57C\uB9CC \uD55C\uB2E4.","\u3010\uD0C0\uB77D\u3011 \uB2F9\uC2E0\uC740 \uB9C8\uC74C\uC18D\uC758 \uC5B4\uB460\uC5D0 \uBA39\uD614\uB2E4. \uB2E4\uC74C \uC138\uC158 \uAC1C\uC2DC \uC2DC\uC5D0, \uD074\uB798\uC2A4 1\uAC1C\uAC00 \u300E\uC554\uD751\u300F\uC774\uB098 \u300E\uBAAC\uC2A4\uD130\u300F\uB85C \uBCC0\uACBD\uB41C\uB2E4!","\u3010\uC608\uC18D\u3011 \uB2F9\uC2E0\uC740 \uC801\uC758 \uB9D0\uC5D0 \uAC70\uC2A4\uB97C \uC218 \uC5C6\uB2E4. \uB2E4\uC74C \uC138\uC158\uC5D0 \uB2F9\uC2E0\uC758 \uC2A4\uD0E0\uC2A4\uB294 \u300E\uC885\uC18D\u300F\uC774 \uB41C\uB2E4.","\u3010\uBC30\uBC18\u3011 \uBC30\uBC18\uC758 \uCDA9\uB3D9. \uC784\uC758\uC758 \uC544\uAD70\uC758 \u3010\uCCB4\uB825\u3011\uC744 1D6\uC810 \uAC10\uC18C\uC2DC\uD0A4\uACE0, \uADF8 \uC790\uB9AC\uC5D0\uC11C \uB3C4\uB9DD\uCE5C\uB2E4.","\u3010\uD3ED\uC8FC\u3011 \uB2F9\uC2E0\uC740 \uC774\uC131\uC744 \uC783\uACE0, \uCDA9\uB3D9\uC5D0 \uB530\uB77C \uD3ED\uC8FC\uD55C\uB2E4! \uAC19\uC740 \uC52C\uC5D0 \uC788\uB294 \uC804\uC6D0\uC758 \u3010\uCCB4\uB825\u3011\uC744 1D6\uC810 \uAC10\uC18C\uC2DC\uD0A8\uB2E4.","\u3010\uC800\uC8FC\u3011 \uB9C8\uC74C\uC758 \uC5B4\uB460\uC774 \uD604\uC7AC\uD654\uD55C \uAC83\uC778\uAC00. \uC801\uC758 \uC6D0\uD55C\uC778\uAC00. \uC800\uC8FC\uC5D0 \uC0BC\uCF1C\uC9C4 \uB2F9\uC2E0\uC740, \uADF8\uC800 \uACE0\uD1B5\uC5D0 \uBAB8\uBD80\uB9BC\uCE60 \uC218\uBC16\uC5D0 \uC5C6\uB2E4.","\u3010\uD3EC\uB85C\u3011 \uB2F9\uC2E0\uC740 \uC801\uC5D0\uAC8C \uC0AC\uB85C\uC7A1\uD600, \uADF8 \uC790\uB9AC\uC5D0\uC11C \uB04C\uB824\uAC14\uB2E4.","\u3010\uB3C4\uC8FC\u3011 \uB2F9\uC2E0\uC740 \uAC81\uC5D0 \uC9C8\uB824, \uB3D9\uB8CC\uB97C \uBC84\uB9AC\uACE0 \uB3C4\uB9DD\uCCE4\uB2E4.","\u3010\uBC29\uC2EC\u3011 \uB2F9\uC2E0\uC740 \uADF8\uC800 \uBA4D\uD558\uB2C8 \uC11C \uC788\uC744 \uC218\uBC16\uC5D0 \uC5C6\uB2E4. \uC815\uC2E0\uC744 \uCC28\uB838\uC744 \uB54C, \uBAA8\uB4E0 \uAC83\uC740 \uB05D\uB098\uC788\uC5C8\uB2E4.","\u3010\uAE30\uC808\u3011 \uB2F9\uC2E0\uC740 \uC758\uC2DD\uC744 \uC783\uC5C8\uB2E4. \uADF8\uB9AC\uACE0 \uC815\uC2E0\uC774 \uB4E4\uBA74 \uBAA8\uB4E0 \uAC83\uC774 \uB05D\uB098\uC788\uC5C8\uB2E4.","\uADF8\uB798\uB3C4 \uC544\uC9C1 \uD3EC\uAE30\uD558\uC9C0 \uC54A\uC544! \uB2F9\uC2E0\uC740 \uBC30\uB4DC\uC5D4\uB4DC\uB97C \uB9DE\uC774\uD558\uC9C0 \uC54A\uC558\uB2E4. \uAE30\uB825\uC758 \u3010\uB099\uC778\u3011\uC744 1\uAC1C \uC9C0\uC6CC\uB3C4 \uC88B\uB2E4."]}}}},a={ko_kr:t};export{a as default,t as ko_kr};
